{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF9 changed the default discriminator property from "Discriminator" to "$type".
            // Existing documents and direct SQL queries use "Discriminator", so keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // EF9 changed id format from "Product|123" to "123".
            // Existing 500K documents use the old compound format — preserve it.
            entity.HasRootDiscriminatorInJsonId(true);

            // HasIndex is removed: EF9 Cosmos provider throws at startup.
            // Manage indexing via Azure Portal, Bicep, or Terraform instead.
        });
    }
}
