class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // EF9 Cosmos raw SQL must use VALUE projection
        var sql = "SELECT VALUE c FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // EF9 Cosmos no longer supports sync I/O — use async
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

